      "line": "                \"content\": \"<file path=\\\"ShenCode/tools/prepare_dataset.py\\\" total_lines=\\\"379\\\" shown_lines=\\\"1-200\\\" truncated=\\\"true\\\" next_start_line=\\\"201\\\">\\n     1│ from __future__ import annotations\\n     2│ \\n     3│ import argparse\\n     4│ import csv\\n     5│ import json\\n     6│ import re\\n     7│ from collections import defaultdict\\n     8│ from pathlib import Path\\n     9│ \\n    10│ \\n    11│ IMAGE_EXTS = {\\\".jpg\\\", \\\".jpeg\\\", \\\".png\\\", \\\".bmp\\\", \\\".webp\\\"}\\n    12│ VIDEO_EXTS = {\\\".mp4\\\", \\\".avi\\\", \\\".mov\\\", \\\".mkv\\\", \\\".webm\\\", \\\".m4v\\\"}\\n    13│ \\n    14│ \\n    15│ def _is_media_file(path: Path) -> bool:\\n    16│     ext = path.suffix.lower()\\n    17│     return ext in IMAGE_EXTS or ext in VIDEO_EXTS\\n    18│ \\n    19│ \\n    20│ def _media_type(path: Path) -> str:\\n    21│     ext = path.suffix.lower()\\n    22│     if ext in IMAGE_EXTS:\\n    23│         return \\\"image\\\"\\n    24│     if ext in VIDEO_EXTS:\\n    25│         return \\\"video\\\"\\n    26│     return \\\"unknown\\\"\\n    27│ \\n    28│ \\n    29│ def _scan_split(raw_dir: Path, split: str) -> list[tuple[str, Path]]:\\n    30│     split_dir = raw_dir / split\\n    31│     if not split_dir.exists():\\n    32│         return []\\n    33│ \\n    34│     pairs: list[tuple[str, Path]] = []\\n    35│     for p in sorted(split_dir.rglob(\\\"*\\\")):\\n    36│         if not p.is_file():\\n    37│             continue\\n    38│         if not _is_media_file(p):\\n    39│             continue\\n    40│         rel = p.relative_to(split_dir)\\n    41│         if len(rel.parts) < 2:\\n    42│             continue\\n    43│         label = rel.parts[0]\\n    44│         pairs.append((label, p))\\n    45│     return pairs\\n    46│ \\n    47│ \\n    48│ def _scan_unsplit(raw_dir: Path) -> list[tuple[str, Path]]:\\n    49│     pairs: list[tuple[str, Path]] = []\\n    50│     for p in sorted(raw_dir.rglob(\\\"*\\\")):\\n    51│         if not p.is_file():\\n    52│             continue\\n    53│         if not _is_media_file(p):\\n    54│             continue\\n    55│         rel = p.relative_to(raw_dir)\\n    56│         if len(rel.parts) < 2:\\n    57│             continue\\n    58│         label = rel.parts[0]\\n    59│         pairs.append((label, p))\\n    60│     return pairs\\n    61│ \\n    62│ \\n    63│ def _parse_sample_id(filename: str) -> str | None:\\n    64│     \\\"\\\"\\\"Extract sample_id from filename like 'signer0_sample1_color.mp4' -> 'signer0_sample1'\\\"\\\"\\\"\\n    65│     match = re.match(r\\\"(signer\\\\d+_sample\\\\d+)\\\", filename)\\n    66│     return match.group(1) if match else None\\n    67│ \\n    68│ \\n    69│ def _load_label_file(label_file: Path) -> dict[str, int]:\\n    70│     \\\"\\\"\\\"Load AUTSL-style label CSV: sample_id,label -> {sample_id: label_id}\\\"\\\"\\\"\\n    71│     labels = {}\\n    72│     with label_file.open(\\\"r\\\", encoding=\\\"utf-8\\\") as f:\\n    73│         reader = csv.reader(f)\\n    74│         for row in reader:\\n    75│             if len(row) >= 2:\\n    76│                 sample_id = row[0].strip()\\n    77│                 label_id = int(row[1].strip())\\n    78│                 labels[sample_id] = label_id\\n    79│     return labels\\n    80│ \\n    81│ \\n    82│ def _scan_autsl_split(\\n    83│     split_dir: Path, label_map: dict[str, int], color_only: bool = True\\n    84│ ) -> list[tuple[str, int, Path]]:\\n    85│     \\\"\\\"\\\"Scan AUTSL split directory and return (sample_id, label_id, path) tuples.\\\"\\\"\\\"\\n    86│     results: list[tuple[str, int, Path]] = []\\n    87│     if not split_dir.exists():\\n    88│         return results\\n    89│ \\n    90│     for p in sorted(split_dir.rglob(\\\"*\\\")):\\n    91│         if not p.is_file():\\n    92│             continue\\n    93│         if not _is_media_file(p):\\n    94│             continue\\n    95│         if color_only and \\\"_depth\\\" in p.name:\\n    96│             continue\\n    97│ \\n    98│         sample_id = _parse_sample_id(p.name)\\n    99│         if sample_id is None:\\n   100│             continue\\n   101│         if sample_id not in label_map:\\n   102│             continue\\n   103│ \\n   104│         label_id = label_map[sample_id]\\n   105│         results.append((sample_id, label_id, p))\\n   106│ \\n   107│     return results\\n   108│ \\n   109│ \\n   110│ def build_manifest_autsl(\\n   111│     raw_dir: Path,\\n   112│     project_root: Path,\\n   113│     splits_config: dict[str, tuple[Path, Path]],\\n   114│     color_only: bool = True,\\n   115│ ) -> tuple[list[dict], dict[int, str]]:\\n   116│     \\\"\\\"\\\"Build manifest for AUTSL dataset using label files.\\n   117│ \\n   118│     Args:\\n   119│         raw_dir: Root raw data directory\\n   120│         project_root: Project root for relative paths\\n   121│         splits_config: {split_name: (video_dir, label_file)} mapping\\n   122│         color_only: If True, only include *_color.mp4 files\\n   123│ \\n   124│     Returns:\\n   125│         (records, id2label) tuple\\n   126│     \\\"\\\"\\\"\\n   127│     records: list[dict] = []\\n   128│     all_label_ids: set[int] = set()\\n   129│ \\n   130│     for split, (video_dir, label_file) in splits_config.items():\\n   131│         if not label_file.exists():\\n   132│             print(\\n   133│                 f\\\"Warning: label file not found: {label_file}, skipping split '{split}'\\\"\\n   134│             )\\n   135│             continue\\n   136│         if not video_dir.exists():\\n   137│             print(\\n   138│                 f\\\"Warning: video dir not found: {video_dir}, skipping split '{split}'\\\"\\n   139│             )\\n   140│             continue\\n   141│ \\n   142│         label_map = _load_label_file(label_file)\\n   143│         all_label_ids.update(label_map.values())\\n   144│ \\n   145│         for sample_id, label_id, path in _scan_autsl_split(\\n   146│             video_dir, label_map, color_only\\n   147│         ):\\n   148│             records.append(\\n   149│                 {\\n   150│                     \\\"split\\\": split,\\n   151│                     \\\"sample_id\\\": sample_id,\\n   152│                     \\\"label_id\\\": label_id,\\n   153│                     \\\"label\\\": str(label_id),\\n   154│                     \\\"path\\\": str(path.relative_to(project_root).as_posix()),\\n   155│                     \\\"media_type\\\": _media_type(path),\\n   156│                     \\\"ext\\\": path.suffix.lower(),\\n   157│                 }\\n   158│             )\\n   159│ \\n   160│     for i, r in enumerate(records):\\n   161│         r[\\\"global_id\\\"] = i\\n   162│ \\n   163│     id2label = {i: str(i) for i in sorted(all_label_ids)}\\n   164│     return records, id2label\\n   165│ \\n   166│ \\n   167│ def build_manifest(raw_dir: Path, project_root: Path, splits: list[str]) -> list[dict]:\\n   168│     split_dirs_exist = any((raw_dir / s).exists() for s in splits)\\n   169│ \\n   170│     records: list[dict] = []\\n   171│     if split_dirs_exist:\\n   172│         for split in splits:\\n   173│             for label, path in _scan_split(raw_dir, split):\\n   174│                 records.append(\\n   175│                     {\\n   176│                         \\\"split\\\": split,\\n   177│                         \\\"label\\\": label,\\n   178│                         \\\"path\\\": str(path.relative_to(project_root).as_posix()),\\n   179│                         \\\"media_type\\\": _media_type(path),\\n   180│                         \\\"ext\\\": path.suffix.lower(),\\n   181│                     }\\n   182│                 )\\n   183│     else:\\n   184│         for label, path in _scan_unsplit(raw_dir):\\n   185│             records.append(\\n   186│                 {\\n   187│                     \\\"split\\\": \\\"unsplit\\\",\\n   188│                     \\\"label\\\": label,\\n   189│                     \\\"path\\\": str(path.relative_to(project_root).as_posix()),\\n   190│                     \\\"media_type\\\": _media_type(path),\\n   191│                     \\\"ext\\\": path.suffix.lower(),\\n   192│                 }\\n   193│             )\\n   194│ \\n   195│     labels = sorted({r[\\\"label\\\"] for r in records})\\n   196│     label2id = {label: i for i, label in enumerate(labels)}\\n   197│ \\n   198│     for i, r in enumerate(records):\\n   199│         r[\\\"sample_id\\\"] = i\\n   200│         r[\\\"label_id\\\"] = label2id[r[\\\"label\\\"]]\\n\\n[TRUNCATED] Showing lines 1-200 of 379. To continue, call read_file with path=\\\"ShenCode/tools/prepare_dataset.py\\\" start_line=201 max_lines=200\\n</file>\"",
